let me know how this works for you... and if you see any major adjustments that need fixing.  



declare upper;

input FastEMALength = 9;

input SlowEMALength = 20;

input VolumeLength = 20;

input ATRLength = 14;

input StartTime = 0935;

input EndTime = 1130;

input VolumeMultiplier = 1.2;

input ATRStretchMultiplier = 0.25;

input UseOpeningRangeFilter = yes;

input OpeningRangeEndTime = 0945;

input UseStrongORBreak = yes;

input UseChopFilter = yes;

input ChopATRThreshold = 0.35;

input UseMTFConfirmation = yes;

input UseADXFilter = yes;

input ADXLength = 14;

input MinADX = 20;

input UseFirstSignalOnly = yes;

input UsePriorCandleConfirmation = yes;

input UseVolumeExpanding = yes;

input ShowLongSignals = yes;

input ShowShortSignals = yes;

input ShowLabels = yes;

input EnableAlerts = yes;

input ShowIVLabel = yes;

input IVLookback = 252;

input IVDangerThreshold = 80.0;

input ShowRiskLines = yes;

input StopATRMult = 1.0;

input TargetATRMult = 1.5;

input ResetLinesOnNewDay = yes;

input UseMomentumExhaustionFilter = no;

input RSILength = 2;

input OverboughtLevel = 85;

input OversoldLevel = 15;

def EMA9 = ExpAverage(close, FastEMALength);

def EMA20 = ExpAverage(close, SlowEMALength);

def VWAPValue = VWAP();

def AvgVol = Average(volume, VolumeLength);

def ATR = Average(TrueRange(high, close, low), ATRLength);

def NewDay = GetYYYYMMDD() <> GetYYYYMMDD()\[1\];

def InTimeWindow = SecondsFromTime(StartTime) >= 0 and SecondsTillTime(EndTime) > 0;

def BullishTrend = EMA9 > EMA20;

def BearishTrend = EMA9 < EMA20;

def EMA9Rising = EMA9 > EMA9\[1\];

def EMA9Falling = EMA9 < EMA9\[1\];

def VWAPRising = VWAPValue > VWAPValue\[1\];

def VWAPFalling = VWAPValue < VWAPValue\[1\];

def BullishCandle = close > open;

def BearishCandle = close < open;

def PriorBull = close\[1\] > open\[1\];

def PriorBear = close\[1\] < open\[1\];

def StrongBullVolume = AvgVol > 0 and volume > AvgVol \* VolumeMultiplier;

def StrongBearVolume = AvgVol > 0 and volume > AvgVol \* VolumeMultiplier;

def VolumeExpanding = volume > volume\[1\];

def NotExtendedLong = (close - VWAPValue) < (ATR \* ATRStretchMultiplier);

def NotExtendedShort = (VWAPValue - close) < (ATR \* ATRStretchMultiplier);

def RSI2 = RSI(length = RSILength);

def Overbought = RSI2 > OverboughtLevel;

def Oversold = RSI2 < OversoldLevel;

def MTF\_Close = close(period = AggregationPeriod.FIVE\_MIN);

def MTF\_EMA9 = ExpAverage(MTF\_Close, FastEMALength);

def MTF\_EMA20 = ExpAverage(MTF\_Close, SlowEMALength);

def MTF\_Bullish = MTF\_EMA9 > MTF\_EMA20;

def MTF\_Bearish = MTF\_EMA9 < MTF\_EMA20;

def ADXVal = DMI(length = ADXLength).ADX;

rec ORHigh = if NewDay then high else if SecondsTillTime(OpeningRangeEndTime) > 0 then Max(high, ORHigh\[1\]) else ORHigh\[1\];

rec ORLow = if NewDay then low else if SecondsTillTime(OpeningRangeEndTime) > 0 then Min(low, ORLow\[1\]) else ORLow\[1\];

def OpeningRangeReady = SecondsTillTime(OpeningRangeEndTime) <= 0;

def StrongORLongBreak = close > ORHigh and open <= ORHigh;

def StrongORShortBreak = close < ORLow and open >= ORLow;

def LongORFilter = !UseOpeningRangeFilter or (OpeningRangeReady and (if UseStrongORBreak then StrongORLongBreak else close > ORHigh));

def ShortORFilter = !UseOpeningRangeFilter or (OpeningRangeReady and (if UseStrongORBreak then StrongORShortBreak else close < ORLow));

def EMASpread = AbsValue(EMA9 - EMA20);

def NotChoppy = !UseChopFilter or ATR <= 0 or (EMASpread / ATR > ChopATRThreshold);

def RawIV = imp\_volatility();

def IVLowest = Lowest(RawIV, IVLookback);

def IVHighest = Highest(RawIV, IVLookback);

def IVRank = if IVHighest > IVLowest then 100 \* (RawIV - IVLowest) / (IVHighest - IVLowest) else 0;

def IVDanger = IVRank >= IVDangerThreshold;

def BaseLongTrigger = InTimeWindow and BullishTrend and EMA9Rising and VWAPRising and EMA9 crosses above VWAPValue and BullishCandle and close > VWAPValue and close > EMA20 and StrongBullVolume and NotExtendedLong and LongORFilter and NotChoppy and (!UseMTFConfirmation or MTF\_Bullish) and (!UseADXFilter or ADXVal >= MinADX) and (!UseMomentumExhaustionFilter or !Overbought) and (!UsePriorCandleConfirmation or PriorBull) and (!UseVolumeExpanding or VolumeExpanding);

def BaseShortTrigger = InTimeWindow and BearishTrend and EMA9Falling and VWAPFalling and EMA9 crosses below VWAPValue and BearishCandle and close < VWAPValue and close < EMA20 and StrongBearVolume and NotExtendedShort and ShortORFilter and NotChoppy and (!UseMTFConfirmation or MTF\_Bearish) and (!UseADXFilter or ADXVal >= MinADX) and (!UseMomentumExhaustionFilter or !Oversold) and (!UsePriorCandleConfirmation or PriorBear) and (!UseVolumeExpanding or VolumeExpanding);

rec LongFiredToday = if NewDay then 0 else if BaseLongTrigger then 1 else LongFiredToday\[1\];

rec ShortFiredToday = if NewDay then 0 else if BaseShortTrigger then 1 else ShortFiredToday\[1\];

def LongTrigger = BaseLongTrigger and (!UseFirstSignalOnly or LongFiredToday\[1\] == 0);

def ShortTrigger = BaseShortTrigger and (!UseFirstSignalOnly or ShortFiredToday\[1\] == 0);

plot LongSignal = if ShowLongSignals and LongTrigger then low - TickSize() \* 2 else Double.NaN;

LongSignal.SetPaintingStrategy(PaintingStrategy.BOOLEAN\_ARROW\_UP);

LongSignal.SetDefaultColor(Color.CYAN);

LongSignal.SetLineWeight(3);

plot ShortSignal = if ShowShortSignals and ShortTrigger then high + TickSize() \* 2 else Double.NaN;

ShortSignal.SetPaintingStrategy(PaintingStrategy.BOOLEAN\_ARROW\_DOWN);

ShortSignal.SetDefaultColor(Color.MAGENTA);

ShortSignal.SetLineWeight(3);

plot FastEMAPlot = EMA9;

FastEMAPlot.SetDefaultColor(Color.GREEN);

FastEMAPlot.SetLineWeight(1);

plot SlowEMAPlot = EMA20;

SlowEMAPlot.SetDefaultColor(Color.YELLOW);

SlowEMAPlot.SetLineWeight(1);

plot VWAPPlot = VWAPValue;

VWAPPlot.SetDefaultColor(Color.WHITE);

VWAPPlot.SetLineWeight(2);

plot ORHighPlot = if UseOpeningRangeFilter and OpeningRangeReady then ORHigh else Double.NaN;

ORHighPlot.SetDefaultColor(Color.DARK\_GREEN);

ORHighPlot.SetStyle(Curve.SHORT\_DASH);

plot ORLowPlot = if UseOpeningRangeFilter and OpeningRangeReady then ORLow else Double.NaN;

ORLowPlot.SetDefaultColor(Color.DARK\_RED);

ORLowPlot.SetStyle(Curve.SHORT\_DASH);

rec ActiveSide = if NewDay and ResetLinesOnNewDay then 0 else if LongTrigger then 1 else if ShortTrigger then -1 else ActiveSide\[1\];

rec EntryPrice = if NewDay and ResetLinesOnNewDay then Double.NaN else if LongTrigger or ShortTrigger then close else EntryPrice\[1\];

rec EntryATR = if NewDay and ResetLinesOnNewDay then Double.NaN else if LongTrigger or ShortTrigger then ATR else EntryATR\[1\];

def LongStopValue = EntryPrice - EntryATR \* StopATRMult;

def LongTargetValue = EntryPrice + EntryATR \* TargetATRMult;

def ShortStopValue = EntryPrice + EntryATR \* StopATRMult;

def ShortTargetValue = EntryPrice - EntryATR \* TargetATRMult;

plot EntryLine = if ShowRiskLines and !IsNaN(EntryPrice) then EntryPrice else Double.NaN;

EntryLine.SetDefaultColor(Color.WHITE);

EntryLine.SetStyle(Curve.SHORT\_DASH);

EntryLine.SetLineWeight(2);

plot StopLine = if ShowRiskLines and ActiveSide == 1 then LongStopValue else if ShowRiskLines and ActiveSide == -1 then ShortStopValue else Double.NaN;

StopLine.SetDefaultColor(Color.RED);

StopLine.SetStyle(Curve.SHORT\_DASH);

StopLine.SetLineWeight(2);

plot TargetLine = if ShowRiskLines and ActiveSide == 1 then LongTargetValue else if ShowRiskLines and ActiveSide == -1 then ShortTargetValue else Double.NaN;

TargetLine.SetDefaultColor(Color.GREEN);

TargetLine.SetStyle(Curve.SHORT\_DASH);

TargetLine.SetLineWeight(2);

def TrendDayBull = OpeningRangeReady and close > ORHigh and ADXVal >= MinADX and MTF\_Bullish and close > VWAPValue;

def TrendDayBear = OpeningRangeReady and close < ORLow and ADXVal >= MinADX and MTF\_Bearish and close < VWAPValue;

def VWAPDistanceATR = if ATR > 0 then (close - VWAPValue) / ATR else 0;

AddLabel(ShowLabels, "EMA9: " + Round(EMA9, 2), if EMA9Rising then Color.GREEN else Color.RED);

AddLabel(ShowLabels, "EMA20: " + Round(EMA20, 2), Color.YELLOW);

AddLabel(ShowLabels, "VWAP: " + Round(VWAPValue, 2), Color.WHITE);

AddLabel(ShowLabels, "Vol x Avg: " + (if AvgVol > 0 then Round(volume / AvgVol, 2) else 0), if AvgVol > 0 and volume > AvgVol \* VolumeMultiplier then [Color.GREEN](http://Color.GREEN) else Color.GRAY);

AddLabel(ShowLabels, "ATR: " + Round(ATR, 2), Color.LIGHT\_GRAY);

AddLabel(ShowLabels, if InTimeWindow then "WINDOW: ON" else "WINDOW: OFF", if InTimeWindow then Color.GREEN else Color.RED);

AddLabel(ShowLabels, if NotChoppy then "REGIME: TRENDABLE" else "REGIME: CHOP", if NotChoppy then Color.GREEN else Color.RED);

AddLabel(ShowLabels, if UseOpeningRangeFilter then "OR FILTER: ON" else "OR FILTER: OFF", if UseOpeningRangeFilter then Color.CYAN else Color.GRAY);

AddLabel(ShowLabels, "MTF: " + (if MTF\_Bullish then "BULL" else if MTF\_Bearish then "BEAR" else "NEUTRAL"), if MTF\_Bullish then Color.GREEN else if MTF\_Bearish then Color.RED else Color.GRAY);

AddLabel(ShowLabels, "ADX: " + Round(ADXVal, 1), if ADXVal >= MinADX then [Color.GREEN](http://Color.GREEN) else Color.GRAY);

AddLabel(ShowLabels, if TrendDayBull then "DAY TYPE: BULL TREND" else if TrendDayBear then "DAY TYPE: BEAR TREND" else "DAY TYPE: MIXED", if TrendDayBull then Color.GREEN else if TrendDayBear then Color.RED else Color.GRAY);

AddLabel(ShowLabels, "VWAP Dist ATR: " + Round(VWAPDistanceATR, 2), if AbsValue(VWAPDistanceATR) < 0.25 then [Color.GREEN](http://Color.GREEN) else Color.YELLOW);

AddLabel(ShowLabels, if UseFirstSignalOnly then "FIRST SIGNAL ONLY: ON" else "FIRST SIGNAL ONLY: OFF", if UseFirstSignalOnly then Color.CYAN else Color.GRAY);

AddLabel(ShowLabels, if UsePriorCandleConfirmation then "PRIOR CANDLE: ON" else "PRIOR CANDLE: OFF", if UsePriorCandleConfirmation then Color.CYAN else Color.GRAY);

AddLabel(ShowLabels, if UseVolumeExpanding then "VOL EXPANDING: ON" else "VOL EXPANDING: OFF", if UseVolumeExpanding then Color.CYAN else Color.GRAY);

AddLabel(ShowIVLabel, "IV Rank Proxy: " + Round(IVRank, 0) + "%", if IVDanger then Color.RED else if IVRank >= 50 then Color.YELLOW else Color.GREEN);

AddLabel(ShowRiskLines and !IsNaN(EntryPrice), "Entry: " + Round(EntryPrice, 2) + " Stop: " + Round(if ActiveSide == 1 then LongStopValue else ShortStopValue, 2) + " Target: " + Round(if ActiveSide == 1 then LongTargetValue else ShortTargetValue, 2), if ActiveSide == 1 then Color.CYAN else if ActiveSide == -1 then Color.MAGENTA else Color.GRAY);

Alert(EnableAlerts and LongTrigger, "ELITE 0DTE LONG", [Alert.BAR](http://Alert.BAR), Sound.Ding);

Alert(EnableAlerts and ShortTrigger, "ELITE 0DTE SHORT", [Alert.BAR](http://Alert.BAR), Sound.Bell);

Alert(EnableAlerts and IVDanger, "IV ELEVATED", [Alert.BAR](http://Alert.BAR), Sound.Ring);
